import * as React from 'react'
import FormRelatePlusDataSelect from './form-relate-plus-data-select'
import FormRelatePlusAddRecordBtn from './form-relate-plus-add-record-btn'
import FormRelatePlusDataShow from './form-relate-plus-data-show'

export interface FormRelatePlusProps {
  relateSchema: {
    relateTo?: string
    relate?: {
      id?: string
    }
    recordSelectType?: 'select' | 'modal'
    selectType?: 'single' | 'multiple'
    showType?: 'select' | 'card' | 'table'
    showField?: string
    allowAdd?: boolean
    editDisabled?: boolean
    createDisabled?: boolean
    relateShowFields?: Array<{
      key: string
      title: string
      fieldSchema?: any
    }>
  } & Record<string, any>
  tableID?: string
  input?: {
    value?: any
    onChange?: (value: any) => void
  }
  value?: any
  onChange?: (value: any) => void
  field?: {
    schema?: Record<string, any>
    displayField?: string
    relateShowFields?: Array<{
      key: string
      title: string
      fieldSchema?: any
    }>
  }
  meta?: {
    data?: {
      disabled?: boolean
    }
  }
  schema?: {
    name?: string
  }
}

const FormRelatePlus: React.FC<FormRelatePlusProps> = (props) => {
  const input = props.input || { value: props.value, onChange: props.onChange }
  // 只传递需要的属性给子组件
  const dataSelectProps: any = {
    relateSchema: props.relateSchema,
    tableID: props.tableID,
    input,
    field: props.field,
    meta: props.meta,
  }

  const addRecordBtnProps = {
    relateSchema: props.relateSchema,
    tableID: props.tableID,
    input: props,
    meta: props.meta,
  }

  const dataShowProps = {
    relateSchema: props.relateSchema,
    input: props,
    field: props.field,
    schema: props.schema,
  }

  if (!props.relateSchema) {
    return <div className="text-sm text-red-500">关联字段配置错误：缺少 relateSchema</div>
  }
  return (
    <div className="flex flex-col items-stretch w-full gap-2">
      <div className="flex flex-row gap-2">
        <FormRelatePlusDataSelect {...dataSelectProps} />
        <FormRelatePlusAddRecordBtn {...addRecordBtnProps} />
      </div>
      <FormRelatePlusDataShow {...dataShowProps} />
    </div>
  )
}

export { FormRelatePlus }
export default FormRelatePlus

import * as React from 'react'
import {
  RelateSelect,
  RelateMultiSelect,
  RelateModelSelect,
} from '@/registry/components/form-relate'
import type { RelateFieldProps } from '@/registry/components/form-relate/types'

export interface FormRelatePlusDataSelectProps extends RelateFieldProps {
  relateSchema: {
    relateTo?: string
    recordSelectType?: 'select' | 'modal'
    selectType?: 'single' | 'multiple'
    showType?: 'select' | 'card' | 'table'
    showField?: string
    allowAdd?: boolean
    editDisabled?: boolean
    createDisabled?: boolean
  } & Record<string, any>
  tableID?: string
}

const FormRelatePlusDataSelect: React.FC<FormRelatePlusDataSelectProps> = (props) => {
  const { relateSchema, tableID, meta, field, input } = props

  // Determine which select component to use
  let SelectComponent: any = RelateModelSelect
  let extraProps: Record<string, any> = {}

  // User/Role special handling would go here if needed
  // For now, we use RelateSelect/RelateMultiSelect/RelateModelSelect based on recordSelectType

  if (relateSchema.recordSelectType === 'select') {
    if (relateSchema.selectType === 'multiple') {
      SelectComponent = RelateMultiSelect
    } else {
      SelectComponent = RelateSelect
    }
  } else if (relateSchema.recordSelectType === 'modal') {
    SelectComponent = RelateModelSelect
    // Set input type to button for card/table show types
    if (['card', 'table'].includes(relateSchema.showType || '')) {
      extraProps.inputType = 'button'
    }
    extraProps.selectType = relateSchema.selectType
  }

  // Handle disabled state
  const isDisabled = meta?.data?.disabled ?? relateSchema.editDisabled ?? false

  if (isDisabled) {
    extraProps.disabled = true
    extraProps.relateSchema = {
      ...relateSchema,
      editDisabled: true,
      createDisabled: true,
    }
  }

  // 构建 field props，确保包含必要的 schema 信息
  const selectProps: any = {
    input,
    meta,
    field: {
      ...field,
      // 为 AsyncSelect 提供带 name 的 schema（与 schemaConverter 的格式一致）
      schema: tableID ? { name: `core/t/${tableID}/d` } : relateSchema,
      displayField: relateSchema.relate?.fields?.[0]?.key || relateSchema.showField || 'name',
      tableID,
      relateShowFields: relateSchema.relateShowFields,
    },
    ...extraProps,
  }

  return (
    <div className="flex flex-row w-full gap-2">
      <SelectComponent {...selectProps} />
    </div>
  )
}

export { FormRelatePlusDataSelect }
export default FormRelatePlusDataSelect

import * as React from 'react'
